package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

public class CSVParserTest {

    private CSVParser parser;
    private Lexer lexerMock;

    @BeforeEach
    public void setUp() throws Exception {
        // Create a CSVParser instance with null reader and format to bypass constructor complexity
        parser = Mockito.mock(CSVParser.class, Mockito.CALLS_REAL_METHODS);

        // Create a mock Lexer
        lexerMock = mock(Lexer.class);

        // Use reflection to set the private lexer field
        Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(parser, lexerMock);
    }

    @Test
    public void testClose_LexerNotNull_ClosesLexer() throws IOException {
        parser.close();
        verify(lexerMock, times(1)).close();
    }

    @Test
    public void testClose_LexerNull_NoException() throws Exception {
        // Set lexer to null
        Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(parser, null);

        assertDoesNotThrow(() -> parser.close());
    }
}
